# --- Password Hashing ---

class PasswordManager:
    """Handles password hashing using Argon2 (preferred) or Werkzeug's bcrypt/scrypt fallback."""

    def __init__(self):
        if HAS_ARGON2:
            self.ph = PasswordHasher(
                time_cost=3,
                memory_cost=65536,
                parallelism=4,
                hash_len=32,
                salt_len=16
            )
        else:
            self.ph = None

    def hash_password(self, password: str) -> str:
        if self.ph:
            return self.ph.hash(password)
        else:
            return generate_password_hash(password, method='scrypt', salt_length=16)

    def verify_password(self, stored_hash: str, password: str) -> bool:
        if self.ph:
            try:
                return self.ph.verify(stored_hash, password)
            except argon2.exceptions.VerifyMismatchError:
                return False
            except argon2.exceptions.VerificationError:
                return False
        else:
            return check_password_hash(stored_hash, password)

    def needs_rehash(self, stored_hash: str) -> bool:
        if self.ph:
            return self.ph.check_needs_rehash(stored_hash)
        return False


password_manager = PasswordManager()


# --- Rate Limiting ---

def get_client_identifier():
    """Get a client identifier for rate limiting."""
    return request.remote_addr or 'unknown'


def is_rate_limited(identifier: str) -> bool:
    """Check if the client is rate limited."""
    now = time.time()

    if identifier not in rate_limit_store:
        rate_limit_store[identifier] = {'attempts': [], 'locked_until': 0}

    record = rate_limit_store[identifier]

    # Check if currently locked out
    if record['locked_until'] > now:
        return True

    # Clean old attempts outside the window
    record['attempts'] = [
        t for t in record['attempts']
        if now - t < RATE_LIMIT_WINDOW_SECONDS
    ]

    return len(record['attempts']) >= RATE_LIMIT_MAX_ATTEMPTS


def record_failed_attempt(identifier: str):
    """Record a failed authentication attempt."""
    now = time.time()

    if identifier not in rate_limit_store:
        rate_limit_store[identifier] = {'attempts': [], 'locked_until': 0}

    record = rate_limit_store[identifier]
    record['attempts'].append(now)

    # Clean old attempts
    record['attempts'] = [
        t for t in record['attempts']
        if now - t < RATE_LIMIT_WINDOW_SECONDS
    ]

    if len(record['attempts']) >= RATE_LIMIT_MAX_ATTEMPTS:
        record['locked_until'] = now + RATE_LIMIT_LOCKOUT_SECONDS


def reset_rate_limit(identifier: str):
    """Reset rate limit on successful authentication."""
    if identifier in rate_limit_store:
        del rate_limit_store[identifier]


# --- Token Management ---

def generate_token(username: str) -> str:
    """Generate a cryptographically secure token."""
    token = secrets.token_urlsafe(48)
    expiration = datetime.utcnow() + timedelta(hours=app.config['TOKEN_EXPIRATION_HOURS'])

    # Store token with metadata
    token_hash = hashlib.sha256(token.encode()).hexdigest()
    tokens_db[token_hash] = {
        'username': username,
        'expires_at': expiration,
        'created_at': datetime.utcnow()
    }

    return token


def verify_token(token: str):
    """Verify a token and return associated user data."""
    token_hash = hashlib.sha256(token.encode()).hexdigest()

    if token_hash not in tokens_db:
        return None

    token_data = tokens_db[token_hash]

    # Check expiration
    if datetime.utcnow() > token_data['expires_at']:
        del tokens_db[token_hash]
        return None

    return token_data


def revoke_token(token: str) -> bool:
    """Revoke a token."""
    token_hash = hashlib.sha256(token.encode()).hexdigest()
    if token_hash in tokens_db:
        del tokens_db[token_hash]
        return True
    return False


def cleanup_expired_tokens():
    """Remove expired tokens from the store."""
    now = datetime.utcnow()
    expired = [
        token_hash for token_hash, data in tokens_db.items()
        if now > data['expires_at']
    ]
    for token_hash in expired:
        del tokens_db[token_hash]


# --- Authentication Decorator ---

def token_required(f):
    """Decorator to protect endpoints with token authentication."""
    @wraps(f)
    def decorated(*args, **kwargs):
        token = None

        # Extract token from Authorization header
        auth_header = request.headers.get('Authorization', '')
        if auth_header.startswith('Bearer '):
            token = auth_header[7:]

        if not token:
            return jsonify({'error': 'Authentication required'}), 401

        token_data = verify_token(token)
        if not token_data:
            return jsonify({'error': 'Invalid or expired token'}), 401

        # Add user info to request context
        request.current_user = token_data['username']
        return f(*args, **kwargs)

    return decorated


